# Prompt Templates Configuration

## JSON Template File

```json
{
  "templates": {
    "qa_basic": {
      "name": "Basic Q&A",
      "version": "1.0.0",
      "system": "You are a helpful assistant.",
      "user": "Question: {question}\n\nAnswer:",
      "variables": ["question"]
    },
    "qa_with_context": {
      "name": "Q&A with Context",
      "version": "1.0.0",
      "system": "You are a helpful assistant. Answer based only on the provided context.",
      "user": "Context:\n{context}\n\nQuestion: {question}\n\nAnswer:",
      "variables": ["context", "question"]
    },
    "extraction": {
      "name": "Data Extraction",
      "version": "1.0.0",
      "system": "You are a data extraction assistant. Extract information and return as JSON.",
      "user": "Extract the following fields: {fields}\n\nText:\n{text}\n\nJSON Output:",
      "variables": ["fields", "text"],
      "response_format": "json"
    }
  }
}
```

## Template Manager

```python
import json
from string import Template

class PromptManager:
    def __init__(self, template_file='prompts.json'):
        with open(template_file) as f:
            self.templates = json.load(f)['templates']

    def get_prompt(self, template_name: str, **kwargs) -> dict:
        template = self.templates[template_name]

        # Validate required variables
        for var in template['variables']:
            if var not in kwargs:
                raise ValueError(f'Missing variable: {var}')

        return {
            'system': template['system'],
            'user': template['user'].format(**kwargs)
        }

# Usage
pm = PromptManager()
prompt = pm.get_prompt('qa_with_context', 
    context='Transformers use attention...',
    question='How does attention work?'
)
```
